String longestPalindrome(String s) {
    int n = s.length();
    String result = "";
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j <= n; j++) {
            String subStr = s.substring(i, j + 1);
            int mid = s.length() / 2;
            if (subStr.equals(subStr.substring(0, mid) + subStr.substring(mid))) {
                if (j - i + 1 > result.length()) {
                    result = subStr;
                }
            }
        }
    }
    return result;
}

